    if (!allowedTraceTypes.includes(traceType)) return false;
    if (!banrenma?.isBanrenmaRevealedSlot?.(alienGameState, alienSlotId)) return false;
    const grid = banrenma?.getTraceGrid?.(alienGameState, alienSlotId);
